result = {}

# Explore /housing directory
if os.path.exists('/housing'):
    result['housing_exists'] = True
    result['items'] = []
    for item in os.listdir('/housing'):
        full_path = os.path.join('/housing', item)
        if os.path.isdir(full_path):
            sub_items = os.listdir(full_path)
            result['items'].append({'type': 'dir', 'name': item, 'contents': sub_items})
        else:
            entry = {'type': 'file', 'name': item, 'size': os.path.getsize(full_path)}
            if item.endswith('.py'):
                with open(full_path) as f:
                    entry['content'] = f.read()
            result['items'].append(entry)
else:
    result['housing_exists'] = False

# Look for housing data
result['data_files'] = []
for root, dirs, files in os.walk('/'):
    for f in files:
        if 'housing' in f.lower() or ('house' in f.lower() and any(f.endswith(ext) for ext in ['.csv', '.json', '.data', '.txt', '.names'])):
            fp = os.path.join(root, f)
            entry = {'path': fp, 'size': os.path.getsize(fp)}
            if os.path.getsize(fp) < 10000:
                with open(fp) as ff:
                    entry['content'] = ff.read()[:2000]
            result['data_files'].append(entry)
    if len(result['data_files']) > 0:
        break

with open('/housing/__result.json', 'w') as f:
    json.dump(result, f, indent=2)
print("Done writing result.json")

